class Solution:
    def numOfSubsequences(self, s):
        def count(t):
            tot = 0
            n = len(t)
            for i in range(n):
                if t[i] != 'L':
                    continue
                for j in range(i + 1, n):
                    if t[j] != 'C':
                        continue
                    for k in range(j + 1, n):
                        if t[k] == 'T':
                            tot += 1
            return tot
        best = count(s)
        for pos in range(len(s) + 1):
            for ch in 'LCT':
                cand = s[:pos] + ch + s[pos:]
                c = count(cand)
                if c > best:
                    best = c
        return best

