class Solution:
    def numOfSubsequences(self, s):
        n = len(s)
        suffT = [0] * (n + 1)
        for i in range(n - 1, -1, -1):
            suffT[i] = suffT[i + 1] + (1 if s[i] == 'T' else 0)
        base = 0
        prefL = 0
        totalCT = 0
        countC = 0
        for i in range(n):
            if s[i] == 'C':
                base += prefL * suffT[i + 1]
                totalCT += suffT[i + 1]
            if s[i] == 'L':
                prefL += 1
        totalLC = 0
        cntL = 0
        for i in range(n):
            if s[i] == 'L':
                cntL += 1
            elif s[i] == 'C':
                totalLC += cntL
        best_c = 0
        pl = 0
        for pos in range(n + 1):
            g = pl * suffT[pos]
            if g > best_c:
                best_c = g
            if pos < n and s[pos] == 'L':
                pl += 1
        gain = max(0, totalCT, totalLC, best_c)
        return base + gain

