var numOfSubsequences = function(s) {
    const n = s.length;
    const suffT = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) suffT[i] = suffT[i + 1] + (s[i] === 'T' ? 1 : 0);
    let base = 0, prefL = 0, totalCT = 0;
    for (let i = 0; i < n; i++) {
        if (s[i] === 'C') { base += prefL * suffT[i + 1]; totalCT += suffT[i + 1]; }
        if (s[i] === 'L') prefL += 1;
    }
    let totalLC = 0, cntL = 0;
    for (let i = 0; i < n; i++) {
        if (s[i] === 'L') cntL += 1;
        else if (s[i] === 'C') totalLC += cntL;
    }
    let bestC = 0, pl = 0;
    for (let pos = 0; pos <= n; pos++) {
        const g = pl * suffT[pos];
        if (g > bestC) bestC = g;
        if (pos < n && s[pos] === 'L') pl += 1;
    }
    const gain = Math.max(0, totalCT, totalLC, bestC);
    return base + gain;
};
